export interface ImportPayload {
  customers: Customer[];
  properties: Property[];
  leases: Lease[];
  rooms: Room[];
  beds: Bed[];
  occupants: OccupantCreate[];
  utilities: Utility[];
  /** Optional. Room-night log entries against hotel-rate leases.
Older backups (pre task #299) won't include this — the
importer treats a missing array as empty.
 */
  roomNightLogs?: RoomNightLog[];
  /** Optional. Renter's / liability insurance certificates on
file for properties. Older backups (pre task #333) won't
include this — the importer treats a missing array as
empty.
 */
  insuranceCertificates?: InsuranceCertificate[];
  /** Optional. Per-property recurring non-rent costs (Task
#497, rent-free mode). Older backups won't include this —
the importer treats a missing array as empty.
 */
  otherCosts?: OtherCost[];
}

